const rawItems = $input.all();
// Only consider real job rows (Supabase returns one empty item when alwaysOutputData and 0 rows)
const jobs = rawItems.filter(item => item.json && item.json.id != null);
const currentJobId = $('Set Job Details').first().json.job_id;
const currentCompanyUrl = $('Set Job Details').first().json.company_url;

// No company_url means we cannot do a company match
if (!currentCompanyUrl || !String(currentCompanyUrl).trim()) {
  return [{ json: { hasCompanyContacts: false, jobIds: [], jobIdsStr: '' } }];
}

// Exclude current job (query already does id neq; this is safety)
const otherJobs = jobs.filter(item => item.json.id !== currentJobId);

if (otherJobs.length === 0) {
  return [{ json: { hasCompanyContacts: false, jobIds: [], jobIdsStr: '' } }];
}

const jobIds = otherJobs.map(j => String(j.json.id));
return [{ json: { hasCompanyContacts: true, jobIds, jobIdsStr: jobIds.join(',') } }];

const companyContacts = $('Fetch Company Contacts').all();
const currentJobContacts = $('Fetch Current Job Contacts').all();
const currentJobId = $('Set Job Details').first().json.job_id;

// Build set of linkedin profiles already linked to current job
const existingLinkedins = new Set(
  currentJobContacts
    .map(item => item.json.linkedin)
    .filter(l => l && String(l).trim())
    .map(l => String(l).trim().toLowerCase())
);

// Dedupe company contacts by linkedin; skip those already in current job
const seenLinkedins = new Set();
const newContacts = [];

for (const item of companyContacts) {
  const linkedin = item.json.linkedin;
  if (!linkedin || !String(linkedin).trim()) continue;
  const key = String(linkedin).trim().toLowerCase();
  if (seenLinkedins.has(key)) continue;
  if (existingLinkedins.has(key)) continue;
  seenLinkedins.add(key);
  newContacts.push({
    json: {
      _skip: false,
      job_id: currentJobId,
      name: item.json.name || '',
      linkedin: item.json.linkedin,
      email: Array.isArray(item.json.email) ? item.json.email : (item.json.email ? [String(item.json.email)] : []),
      email_sent_at: null,
      email_thread_id: null,
      followup1_sent_at: null,
      followup2_sent_at: null,
      reply_received: false
    }
  });
}

if (newContacts.length === 0) {
  return [{ json: { _skip: true } }];
}

return newContacts;

function toEmailArray(j) {
  const raw = j.emails ?? j.email ?? j.emailAddresses ?? j.contactEmail ?? j.to ?? j.toEmail;
  if (raw != null) {
    if (Array.isArray(raw)) {
      const arr = raw.map((e) => (typeof e === "string" ? e : e?.email ?? e?.address ?? e?.value ?? "")).filter((s) => typeof s === "string" && s.length > 0);
      if (arr.length) return arr;
    } else {
      const s = String(raw);
      if (s) return [s];
    }
  }
  const collected = [];
  for (const key of Object.keys(j)) {
    if (!/email/i.test(key)) continue;
    const v = j[key];
    if (Array.isArray(v)) v.forEach((e) => { const s = typeof e === "string" ? e : e?.email ?? e?.address ?? e?.value; if (s) collected.push(String(s)); });
    else if (v != null && v !== "") collected.push(String(v));
  }
  return collected;
}

function ensureEmailArray(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === "string") return v ? [v] : [];
  return [];
}

const items = $input.all().filter((i) => !i.json?.cellValue && (i.json?.id != null || i.json?.name != null || i.json?.firstName != null));
if (items.length === 0) {
  return [{ json: { id: "", name: "", linkedin: "", email: [], emailSent: "", emailThread: "", followup1: "", followup2: "" } }];
}

const newRecords = items.map(item => {
  const j = item.json;
  return {
    job_id: $('Set Job Details').first().json.job_id,
    name: String(j.firstName || j.lastName || ""),
    linkedin: String(j.linkedinUrl || ""),
    email: toEmailArray(j),
    emailSent: "",
    emailThread: "",
    followup1: "",
    followup2: "",
    reply_received: false
  };
});

return newRecords.map(r => ({ json: { ...r, email: ensureEmailArray(r.email) } }));
